import React from "react";
import { Chip } from "@mui/material";

const skills = {
  languages: [
    { name: "HTML", emoji: "🌐", color: "#2196F3" }, // Blue
    { name: "CSS", emoji: "🎨", color: "#E91E63" }, // Pink
    { name: "JavaScript", emoji: "⚡", color: "#4CAF50" }, // Green
    { name: "TypeScript", emoji: "🛠️", color: "#00BCD4" }, // Cyan
    { name: "Python", emoji: "🐍", color: "#FF9800" }, // Orange
  ],
  frameworks: [
    { name: "React", emoji: "⚛️", color: "#3F51B5" }, // Indigo
    { name: "React Native", emoji: "📱", color: "#673AB7" }, // Deep Purple
    { name: "Django", emoji: "🐍", color: "#8BC34A" }, // Light Green
  ],
  databases: [
    { name: "PostgreSQL", emoji: "🐘", color: "#336791" }, // Blue
    { name: "SQL", emoji: "🗄️", color: "#4479A1" }, // Blue
    { name: "MySQL", emoji: "🐬", color: "#F29111" }, // Orange
    { name: "NoSQL", emoji: "📂", color: "#6B57FF" }, // Purple
  ],
  tools: [
    { name: "Share Hosting", emoji: "📡", color: "#795548" }, // Brown
  ],
  cloud: [
    { name: "Azure", emoji: "☁️", color: "#03A9F4" }, // Light Blue
    { name: "Digital Ocean", emoji: "🌊", color: "#009688" }, // Teal
  ],
  os: [
    { name: "Mac", emoji: "🍏", color: "#607D8B" }, // Blue Grey
    { name: "Windows", emoji: "🖥️", color: "#1E88E5" }, // Dark Blue
    { name: "Linux", emoji: "🐧", color: "#000000" } // Black
  ],
  others: [
    // Add additional tools or technologies here if needed
  ]
};


export default function Skills() {



  return (
    <section className="skills">
      <div className="section-header">
        <h2><span className="accent">#</span>skills</h2>
      </div>

      <div className="skills-content">
        <div className="geometric-elements">
          <div className="dot-pattern-2"></div>
          <div className="square-element"></div>
          <div className="dot-pattern-3"></div>
          <div className="square-element-2"></div>
          <div className="rect-element"></div>
        </div>

        <div className="skills-grid">
        {skills.map((skill, index) => (
          <div className="skill-category"   key={index}>
            <h3>{skill.emoji}</h3>
            <ul>
              <li>{skill.name}</li>
              <li>Python JavaScript</li>
            </ul>
          </div>
))}

        </div>
      </div>
    </section>
  );
}
